if (action === "get_storage_preview") {
    const { bucket, path, is_image } = payload;
    if (is_image) {
        const { data, error } = await supabase.storage.from(bucket).createSignedUrl(path, 300); // 5 min access
        if (error) throw error;
        return new Response(JSON.stringify({ url: data.signedUrl }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    } else {
        const { data, error } = await supabase.storage.from(bucket).download(path);
        if (error) throw error;
        const text = await data.text();
        return new Response(JSON.stringify({ content: text }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }
}

