2250 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2251 |     function applyLocalPatch(content, ops) {
2252 |         let lines = content.split('\n');
2253 |         let logs = [];
2254 |         let success = true;
2255 | 
2256 |         if (typeof ops === 'string') {
2257 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2258 |         }
2259 | 
2260 |         ops.forEach(op => {
2261 |             if (op.action === 'comment') return;
2262 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2263 |             
2264 |             if (op.action === 'replace_block') {
2265 |                 // Strategy 1: Exact String Match (Fastest)
2266 |                 const currentStr = lines.join('\n');
2267 |                 if (currentStr.includes(op.find_block)) {
2268 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2269 |                     logs.push('Exact match applied');
2270 |                     return;
2271 |                 }
2272 | 
2273 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2274 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2275 |                 if (searchLines.length === 0) return;
2276 | 
2277 |                 let matchStart = -1;
2278 |                 let matchEnd = -1;
2279 | 
2280 |                 // Scan file lines
2281 |                 for (let i = 0; i < lines.length; i++) {
2282 |                     // If first line matches (ignoring whitespace)
2283 |                     if (lines[i].trim() === searchLines[0]) {
2284 |                         // Check subsequent lines
2285 |                         let allMatch = true;
2286 |                         let fileOffset = 0;
2287 |                         let searchOffset = 1;
2288 |                         
2289 |                         while (searchOffset < searchLines.length) {
2290 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2291 |                             const nextFile = lines[i + fileOffset + 1].trim();
2292 |                             // Skip empty lines in file if they aren't in search block
2293 |                             if (nextFile === '') {
2294 |                                 fileOffset++;
2295 |                                 continue;
2296 |                             }
2297 |                             if (nextFile !== searchLines[searchOffset]) {
2298 |                                 allMatch = false;
2299 |                                 break;
2300 |                             }
2301 |                             fileOffset++;
2302 |                             searchOffset++;
2303 |                         }
2304 | 
2305 |                         if (allMatch) {
2306 |                             matchStart = i;
2307 |                             matchEnd = i + fileOffset;
2308 |                             break;
2309 |                         }
2310 |                     }
2311 |                 }
2312 | 
2313 |                 if (matchStart !== -1) {
2314 |                     // Replace the range of lines
2315 |                     const replacement = op.replace_with.split('\n');
2316 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2317 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2318 |                 } else {
2319 |                     success = false;
2320 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2321 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2322 |                 }
2323 |             }
2324 |         });
2325 |         return { content: lines.join('\n'), success, logs };
2326 |     }
