2330 |     async function runAutoFixLoop(name, code, errorList) {
2331 |         const status = document.getElementById('ef-status-msg');
2332 |         let currentCode = code;
2333 |         let currentErrors = errorList;
2334 | 
2335 |         // Fix one by one (recursive loop)
2336 |         async function fixNext(index) {
2337 |             if (index >= currentErrors.length) return true; // All initial errors processed
2338 | 
2339 |             const err = currentErrors[index];
2340 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2341 |             status.style.color = "#eab308"; // Dev yellow
2342 | 
2343 |             try {
2344 |                 // 1. Get Patch from AI
2345 |                 const res = await fetch(CONFIG.funcUrl, { 
2346 |                     method: 'POST', 
2347 |                     headers: {'Content-Type': 'application/json'},
2348 |                     body: apiBody({ 
2349 |                         action: 'propose_syntax_fix', 
2350 |                         code: currentCode, 
2351 |                         error: err 
2352 |                     })
2353 |                 });
2354 |                 const data = await res.json();
2355 |                 const ops = data.operations;
2356 | 
2357 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2358 | 
2359 |                 // 2. Apply Patch Locally
2360 |                 const patchResult = applyLocalPatch(currentCode, ops);
2361 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2362 | 
2363 |                 currentCode = patchResult.content;
2364 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2365 | 
2366 |                 // 3. Re-Validate
2367 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2368 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2369 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2370 |                 });
2371 |                 const scanData = await scanRes.json();
2372 | 
2373 |                 if (scanData.valid) {
2374 |                     status.innerText = "✅ Syntax Fixed!";
2375 |                     return true;
2376 |                 } else {
2377 |                     // If errors remain, update list and Prompt user
2378 |                     currentErrors = scanData.errors;
2379 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2380 |                         // Recursively fix the *new* first error (since layout changed)
2381 |                         return await fixNext(0);
2382 |                     } else {
2383 |                         return false;
2384 |                     }
2385 |                 }
2386 | 
2387 |             } catch (e) {
2388 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2389 |                     return await fixNext(index);
2390 |                 } else {
2391 |                     return false;
2392 |                 }
2393 |             }
2394 |         }
2395 | 
2396 |         return await fixNext(0);
2397 |     }
