5158 |     function formatBytes(bytes) {
5159 |         if (!bytes) return '0 B';
5160 |         const k = 1024;
5161 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5162 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5163 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5164 |     }
