5166 |     function timeAgo(dateString) {
5167 |         const date = new Date(dateString);
5168 |         const now = new Date();
5169 |         const seconds = Math.floor((now - date) / 1000);
5170 |         if (seconds < 10) return 'just now';
5171 |         if (seconds < 60) return seconds + 's ago';
5172 |         const minutes = Math.floor(seconds / 60);
5173 |         if (minutes < 60) return minutes + 'm ago';
5174 |         const hours = Math.floor(minutes / 60);
5175 |         if (hours < 24) return hours + 'h ago';
5176 |         return date.toLocaleDateString();
5177 |     }
