5379 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5380 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5381 |         
5382 |         const navItems = document.querySelectorAll('.nav-item');
5383 |         switchTab(tabId, navItems[navIndex]);
5384 | 
5385 |         const scrollContainer = document.querySelector('.main-view');
5386 |         let retryCount = 0;
5387 |         const MAX_RETRIES = 5;
5388 | 
5389 |         const attemptNavigation = async () => {
5390 |             const element = document.querySelector(selector);
5391 |             
5392 |             if (element) {
5393 |                 console.log("[DeepJump] Element found. Scrolling...");
5394 |                 
5395 |                 // Wait for any tab transition animations
5396 |                 await new Promise(r => setTimeout(r, 300));
5397 | 
5398 |                 let offsetTop = 0;
5399 |                 let curr = element;
5400 |                 while (curr && curr !== scrollContainer) {
5401 |                     offsetTop += curr.offsetTop;
5402 |                     curr = curr.offsetParent;
5403 |                 }
5404 | 
5405 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5406 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5407 | 
5408 |                 // Visual Highlight
5409 |                 element.style.transition = 'all 0.5s ease';
5410 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5411 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5412 |                 setTimeout(() => {
5413 |                     element.style.backgroundColor = '';
5414 |                     element.style.boxShadow = '';
5415 |                 }, 3000);
5416 |                 
5417 |                 console.groupEnd();
5418 |                 return true;
5419 |             }
5420 | 
5421 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5422 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5423 |                 retryCount++;
5424 |                 showGlobalToast("🔍 Searching deeper...");
5425 |                 
5426 |                 await loadMoreFn(); 
5427 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5428 |                 return attemptNavigation();
5429 |             }
5430 | 
5431 |             console.error("[DeepJump] Failed: Element not found after retries.");
5432 |             showGlobalToast("Entry not found in recent history.", true);
5433 |             console.groupEnd();
5434 |             return false;
5435 |         };
5436 | 
5437 |         setTimeout(attemptNavigation, 100);
5438 |     }
