6441 |         document.body.appendChild(toast);
6442 | 
6443 |         pendingImportFiles = [];
6444 | 
6445 |         try {
6446 |             if (file.name.endsWith('.zip')) {
6447 |                 const zip = await JSZip.loadAsync(file);
6448 |                 const promises = [];
6449 |                 zip.forEach((relativePath, zipEntry) => {
6450 |                     if (!zipEntry.dir) {
6451 |                         promises.push(zipEntry.async("string").then(content => {
6452 |                             pendingImportFiles.push({ path: relativePath, content: content });
6453 |                         }));
6454 |                     }
6455 |                 });
6456 |                 await Promise.all(promises);
6457 |             } 
