6460 |                 // Parse "FILE: path\nContent" format
6461 |                 // Split by "\n\nFILE: " to handle multiple files, assuming double newline separator from export
6462 |                 const chunks = text.split(/\n\nFILE: /g);
6463 |                 
6464 |                 chunks.forEach((chunk, index) => {
6465 |                     // Handle first chunk edge case if it starts with "FILE: "
6466 |                     let cleanChunk = chunk;
6467 |                     if (index === 0 && chunk.startsWith("FILE: ")) cleanChunk = chunk.substring(6);
6468 |                     
6469 |                     const firstLineEnd = cleanChunk.indexOf('\n');
6470 |                     if (firstLineEnd !== -1) {
6471 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
6472 |                         const content = cleanChunk.substring(firstLineEnd + 1);
6473 |                         if (path) pendingImportFiles.push({ path, content });
6474 |                     }
6475 |                 });
6476 |             } 
6477 |             else {
6478 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
6479 |             }
6480 | 
6481 |             toast.remove();
6482 |             document.getElementById('import-count').innerText = `${pendingImportFiles.length} files extracted.`;
