6484 |             document.getElementById('import-target-folder').value = "";
6485 |             document.getElementById('import-modal').style.display = 'flex';
6486 | 
6487 |         } catch (e) {
6488 |             toast.remove();
6489 |             alert("Parse Error: " + e.message);
6490 |         }
6491 |         
6492 |         input.value = ''; // Reset input
6493 |     }
