7772 |     function extractTableNames(sql) {
7773 |         if (!sql) return [];
7774 |         const tables = [];
7775 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7776 |         
7777 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7778 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7779 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7780 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7781 | 
7782 |         let match;
7783 |         while ((match = fromRegex.exec(sql)) !== null) {
7784 |             const name = match[1];
7785 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7786 |                 tables.push(name);
7787 |             }
7788 |         }
7789 |         
7790 |         while ((match = metaRegex.exec(sql)) !== null) {
7791 |             const name = match[1];
7792 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7793 |                 tables.push(name);
7794 |             }
7795 |         }
7796 | 
7797 |         return tables;
7798 |     }
7799 | 
7800 |     function convertToCSV(resultObj) {
7801 |         const data = resultObj.data || [];
7802 |         if (!data.length) return '';
7803 |         
7804 |         const tables = extractTableNames(resultObj.sql);
7805 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7806 | 
7807 |         const headers = Object.keys(data[0]);
7808 |         const rows = data.map(row => 
7809 |             headers.map(header => {
7810 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7811 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7812 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7813 |             }).join(',')
7814 |         );
7815 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7816 |     }
