async function previewStorageObject(name, mimetype) {
    const overlay = document.getElementById('storage-preview-overlay');
    const body = document.getElementById('sp-body');
    const title = document.getElementById('sp-title');
    const path = (storageCurrentPath.length > 0 ? storageCurrentPath.join('/') + '/' : '') + name;

    title.innerText = name;
    overlay.classList.add('active');
    body.innerHTML = '<div style="color:var(--ai-accent); font-size:12px;">Loading Preview...</div>';

    const isImg = mimetype && mimetype.startsWith('image/');

    try {
        const res = await fetch(CONFIG.funcUrl, { 
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'get_storage_preview', bucket: storageCurrentBucket, path: path, is_image: isImg })
        });
        const data = await res.json();

        if (isImg) {
            body.innerHTML = `<img src="${data.url}" style="max-width:100%; max-height:100%; border-radius:8px; box-shadow:0 5px 20px rgba(0,0,0,0.5);">`;
        } else {
            body.innerHTML = `<pre style="width:100%; height:100%; margin:0; padding:15px; font-family:'JetBrains Mono'; font-size:12px; color:#ccc; white-space:pre-wrap; word-break:break-all;">${escapeHtml(data.content || 'File is empty or not textual.')}</pre>`;
        }
    } catch(e) { body.innerHTML = `<div style="color:var(--danger);">Failed: ${e.message}</div>`; }
}

function renderStorageList() {
